// frank_go: local tsumego database with difficulty-based querying.
//
// The database is data/tsumego/index.json, generated by
// scripts/frank/build-tsumego-index.mjs from the bundled SGF collections
// (see data/SOURCES.md). Problems carry a `level` from 1 (easiest) to 10.

import {readFileSync} from 'fs'
import {join} from 'path'
import {locateData} from '../paths.js'

// Deterministic RNG (mulberry32) so shuffling is testable and practice
// sessions can be replayed from a seed.
export function createRng(seed = Date.now()) {
  let a = seed >>> 0
  return () => {
    a |= 0
    a = (a + 0x6d2b79f5) | 0
    let t = Math.imul(a ^ (a >>> 15), 1 | a)
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296
  }
}

export function defaultIndexPath() {
  return locateData(join('tsumego', 'index.json'))
}

export class ProblemStore {
  constructor(index) {
    if (index == null || !Array.isArray(index.problems)) {
      throw new Error('ProblemStore: invalid index')
    }

    this.index = index
    this.byId = new Map(index.problems.map((problem) => [problem.id, problem]))
  }

  static fromFile(indexPath = defaultIndexPath()) {
    if (indexPath == null) {
      throw new Error(
        'ProblemStore: could not locate data/tsumego/index.json — ' +
          'run `node scripts/frank/build-tsumego-index.mjs`',
      )
    }

    return new ProblemStore(JSON.parse(readFileSync(indexPath, 'utf8')))
  }

  get collections() {
    return this.index.collections
  }

  get size() {
    return this.index.problems.length
  }

  getById(id) {
    return this.byId.get(id) || null
  }

  query({
    level = null,
    minLevel = 1,
    maxLevel = 10,
    collection = null,
    category = null,
    toPlay = null,
    limit = Infinity,
    shuffleSeed = null,
  } = {}) {
    if (level != null) {
      minLevel = level
      maxLevel = level
    }

    let result = this.index.problems.filter(
      (problem) =>
        problem.level >= minLevel &&
        problem.level <= maxLevel &&
        (collection == null || problem.collection === collection) &&
        (category == null || problem.category === category) &&
        (toPlay == null || problem.toPlay === toPlay),
    )

    if (shuffleSeed != null) {
      let rng = createRng(shuffleSeed)

      for (let i = result.length - 1; i > 0; i--) {
        let j = Math.floor(rng() * (i + 1))
        ;[result[i], result[j]] = [result[j], result[i]]
      }
    }

    return result.slice(0, limit)
  }

  randomProblem(filter = {}, rng = createRng()) {
    let matches = this.query({...filter, limit: Infinity, shuffleSeed: null})
    if (matches.length === 0) return null

    return matches[Math.floor(rng() * matches.length)]
  }

  categories() {
    return [...new Set(this.index.problems.map((problem) => problem.category))]
  }

  stats() {
    let byLevel = {}

    for (let problem of this.index.problems) {
      byLevel[problem.level] = (byLevel[problem.level] || 0) + 1
    }

    return {total: this.size, byLevel}
  }
}

// Renders a problem as a standalone SGF so it can be loaded through
// Sabaki's regular file loading pipeline.
export function problemToSgf(problem) {
  let list = (values) => values.map((vertex) => `[${vertex}]`).join('')
  let parts = [
    `;GM[1]FF[4]CA[UTF-8]AP[frank_go]SZ[${problem.size}]`,
    `GN[${problem.id}]`,
    `PL[${problem.toPlay}]`,
  ]

  if (problem.AB.length > 0) parts.push(`AB${list(problem.AB)}`)
  if (problem.AW.length > 0) parts.push(`AW${list(problem.AW)}`)

  let colorName = problem.toPlay === 'W' ? 'White' : 'Black'
  parts.push(`C[${problem.title} — ${colorName} to play.]`)

  return `(${parts.join('')})`
}

let sharedStore = null

export function getSharedStore() {
  if (sharedStore == null) {
    sharedStore = ProblemStore.fromFile()
  }

  return sharedStore
}
